    description: "Another iteration of the closed-loop SEPIC converter. This specific model heavily emphasizes the use of an embedded PID script block for voltage control alongside wireless routing logic (GOTO/FROM tags) for the gate signals, ensuring maximum layout clarity.",
    components: [{"id":"V1","type":"V","x":-220,"y":0,"rotation":0,"parameters":{"value":"24"},"lastClickTime":1783147574385},{"id":"C1","type":"C","x":-100,"y":0,"rotation":0,"parameters":{"C":"100u","esr":"10m","vC0":"0"},"lastClickTime":1782747358045},{"id":"L1","type":"L","x":-40,"y":-120,"rotation":90,"parameters":{"L":"1m","esr":"50m","iL0":"0"},"lastClickTime":1783167125962},{"id":"C2","type":"C","x":160,"y":-120,"rotation":90,"parameters":{"C":"10u","esr":"10m","vC0":"0"},"lastClickTime":1783167121774},{"id":"L2","type":"L","x":260,"y":0,"rotation":180,"parameters":{"L":"1m","esr":"50m","iL0":"0"},"lastClickTime":1783167131084},{"id":"C3","type":"C","x":420,"y":0,"rotation":0,"parameters":{"C":"100u","esr":"10m","vC0":"0"},"lastClickTime":1783167133534},{"id":"R1","type":"R","x":520,"y":0,"rotation":0,"parameters":{"value":"10","esr":"0"},"lastClickTime":1783167129336},{"id":"D1","type":"D","x":340,"y":-120,"rotation":270,"parameters":{"Vd":"0.7","Ron":"1m","Roff":"1M"}},{"id":"CSCRIPT1","type":"CSCRIPT","x":100,"y":180,"rotation":0,"parameters":{"timestep":"0","plot_custom_vars":"","code":"// ─── ZONE 1: Parameters (editable in properties panel) ───\nconst double V_ref = 12.0;    // Target output voltage (V)\nconst double Kp = 0.01;       // Proportional gain\nconst double Ki = 10.0;      // Integral gain\nconst double Kd = 0.00001;    // Derivative gain\nconst double fc = 10000.0;   // Switching frequency (Hz)\nconst double dt = 1e-6;       // Simulation step size (s)\nconst double D_max = 0.85;     // Maximum allowed duty cycle\nconst double D_min = 0.05;     // Minimum allowed duty cycle\n\n// ─── ZONE 2: State Variables (persistent across time steps) ───\ndouble integrator = 0.0;      // Persistent integrator state\ndouble prev_error = 0.0;      // Persistent error tracking state\ndouble ramp = 0.0;            // Carrier ramp accumulator\n\n// ─── ZONE 3: Step Function (runs every time step) ───\nvoid step() {\n    // 1. Read Sensed Output Voltage V_C3 from Input Pin 0\n    double v_out = inputs[0]; \n    \n    // 2. Compute Voltage Tracking Error\n    double error = V_ref - v_out;\n\n    // 3. Compute PID Controller Outputs\n    double P = Kp * error;\n    double new_integrator = integrator + Ki * error * dt;\n    double D_term = Kd * (error - prev_error) / dt;\n\n    // Total raw control signal (ideal duty cycle)\n    double duty = P + new_integrator + D_term;\n\n    // 4. Clamping and Anti-Windup Logic\n    if (duty > D_max) {\n        duty = D_max;\n        if (error < 0.0) { // Only update integrator if it helps clear saturation\n            integrator = new_integrator;\n        }\n    } else if (duty < D_min) {\n        duty = D_min;\n        if (error > 0.0) {\n            integrator = new_integrator;\n        }\n    } else {\n        integrator = new_integrator;\n    }\n    \n    // Save current error for the next step's derivative action\n    prev_error = error;\n\n    // 5. Sawtooth Carrier Generator\n    double next_ramp = ramp + fc * dt;\n    ramp = (next_ramp >= 1.0) ? next_ramp - 1.0 : next_ramp;\n\n    // 6. Generate PWM Modulation\n    double gate = (ramp < duty) ? 1.0 : 0.0;\n\n    // 7. Drive MOSFET1 Control Signal\n    outputs[0] = gate;\n}","fc":"10000.0","dt":"1e-6","ramp":"0.0","plot_disabled_pins":"","V_ref":"12.0","Kp":"0.01","Ki":"10.0","Kd":"0.00001","D_max":"0.85","D_min":"0.05","integrator":"0.0","prev_error":"0.0"},"lastClickTime":1783167137091},{"id":"VM1","type":"VM","x":660,"y":-40,"rotation":0,"parameters":{},"lastClickTime":1782747167067},{"id":"vgFET1","type":"vg-FET","x":80,"y":-20,"rotation":0,"parameters":{"Ron":"10m","Roff":"1M","Gate_Signal_Label":"S1"},"lastClickTime":1783167135920},{"id":"GOTO_SIG1","type":"GOTO_SIG","x":240,"y":180,"rotation":0,"parameters":{"tag":"S1"},"lastClickTime":1783147664980},{"id":"INTERNAL_VAR1","type":"INTERNAL_VAR","x":-40,"y":180,"rotation":0,"parameters":{"probe_target":"V_R1"},"lastClickTime":1783148519692}],
